'use client';

import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { MeshDistortMaterial, Float, Sphere, Icosahedron, Points, PointMaterial } from '@react-three/drei';
import * as THREE from 'three';

export default function HeroEnvironment() {
  const meshRef = useRef<THREE.Mesh>(null);
  const groupRef = useRef<THREE.Group>(null);
  const pointsPositions = useMemo(() => {
    const pos = new Float32Array(500 * 3);
    for (let i = 0; i < 500; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 20;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 20;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 10;
    }
    return pos;
  }, []);

  useFrame((state) => {
    const { clock, mouse } = state;
    const t = clock.getElapsedTime();

    if (meshRef.current) {
      meshRef.current.rotation.x = t * 0.1;
      meshRef.current.rotation.y = t * 0.15;
    }

    if (groupRef.current) {
      // Gentle tilt following mouse
      groupRef.current.rotation.y = THREE.MathUtils.lerp(groupRef.current.rotation.y, mouse.x * 0.3, 0.05);
      groupRef.current.rotation.x = THREE.MathUtils.lerp(groupRef.current.rotation.x, -mouse.y * 0.3, 0.05);
    }
  });

  return (
    <group ref={groupRef}>
      <Float speed={2} rotationIntensity={0.5} floatIntensity={1}>
        <Icosahedron ref={meshRef} args={[1, 15]} position={[2, 0, 0]}>
          <MeshDistortMaterial
            color="#0ea5e9"
            speed={3}
            distort={0.4}
            radius={1}
            wireframe
            transparent
            opacity={0.3}
          />
        </Icosahedron>
      </Float>

      {/* Internal Core Glow */}
      <Sphere args={[0.5, 32, 32]} position={[2, 0, 0]}>
        <meshBasicMaterial color="#0ea5e9" transparent opacity={0.1} />
      </Sphere>

      {/* Floating Particle Field */}
      <Points positions={pointsPositions}>
        <PointMaterial
          transparent
          color="#0ea5e9"
          size={0.05}
          sizeAttenuation={true}
          depthWrite={false}
          opacity={0.2}
          blending={THREE.AdditiveBlending}
        />
      </Points>

      {/* Ambient Lighting */}
      <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} intensity={2} color="#0ea5e9" />
      <pointLight position={[-10, -10, -10]} intensity={1} color="#8b5cf6" />
      <ambientLight intensity={0.5} />
    </group>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { motion, AnimatePresence, useScroll, useMotionValueEvent } from 'framer-motion';
import { PhoneCall, Zap } from 'lucide-react';
import Image from 'next/image';

const navLinks = [
  { href: '/', label: 'Home' },
  { href: '/services', label: 'Services' },
  { href: '/ai-solutions', label: 'AI Solutions' },
  { href: '/portfolio', label: 'Portfolio' },
  { href: '/about', label: 'About' },
  { href: '/contact', label: 'Contact' },
];

export default function Navbar() {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const pathname = usePathname();

  const [showSticky, setShowSticky] = useState(false);
  const { scrollY } = useScroll();

  useMotionValueEvent(scrollY, "change", (latest) => {
    setScrolled(latest > 50);
    setShowSticky(latest > 600);
  });

  return (
    <motion.nav
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.6, ease: 'easeOut' }}
      className={`fixed top-8 left-0 right-0 z-50 px-6 transition-all duration-500`}
    >
      <div className="max-w-[1550px] mx-auto flex items-center justify-between">
        {/* Logo */}
        <Link href="/" className="flex items-center gap-3 group">
          <div className="relative w-12 h-12 flex items-center justify-center transition-all duration-300 group-hover:scale-105">
            <div className="absolute inset-0 bg-blue-400/20 blur-xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity" />
            <Image 
              src="/logo.png" 
              alt="Vedastra Logo" 
              width={48} 
              height={48} 
              className="relative z-10 w-auto h-10 object-contain brightness-110"
            />
          </div>
          <span className="hidden sm:block font-heading font-bold text-xl tracking-tight uppercase bg-clip-text text-transparent bg-gradient-to-r from-white to-white/60">
            Vedastra
          </span>
        </Link>

        {/* Desktop Navigation (Pill shape) */}
        <div className="hidden lg:flex items-center gap-1 bg-white/[0.05] backdrop-blur-[16px] border border-white/10 rounded-full px-4 py-2 shadow-2xl">
          {navLinks.map((link) => {
            const isActive = pathname === link.href;
            return (
              <Link
                key={link.href}
                href={link.href}
                className={`px-5 py-2 rounded-full text-sm font-medium transition-all duration-300 relative z-10 ${
                  isActive
                    ? 'text-white'
                    : 'text-white/70 hover:text-white'
                }`}
              >
                {link.label}
                {isActive && (
                  <motion.div
                    layoutId="activeNavPill"
                    className="absolute inset-0 bg-white/10 rounded-full -z-10"
                    transition={{ type: 'spring', stiffness: 380, damping: 30 }}
                  />
                )}
              </Link>
            );
          })}
        </div>

        {/* Right Actions */}
        <div className="hidden lg:flex items-center gap-4">
          <AnimatePresence>
            {showSticky && (
              <motion.div
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 20 }}
              >
                <Link
                  href="/contact"
                  className="bg-blue-400 text-black px-6 py-2.5 rounded-full text-sm font-bold shadow-[0_0_20px_rgba(14,165,233,0.3)] hover:scale-105 transition-all flex items-center gap-2"
                >
                  <PhoneCall className="w-4 h-4" /> Start Your Project
                </Link>
              </motion.div>
            )}
          </AnimatePresence>
          
          <div className="flex items-center gap-6 bg-white/[0.02] backdrop-blur-[12px] border border-white/5 rounded-full p-1.5 pr-2">
            <div className="flex items-center gap-2 pl-4 pr-2 font-mono text-[10px] uppercase tracking-[0.2em] text-white/50">
              <span className="w-1.5 h-1.5 rounded-full bg-blue-400 animate-pulse-fast inline-block" />
              System Online
            </div>
            {!showSticky && (
              <Link
                href="/contact"
                className="bg-white text-black hover:bg-blue-400 hover:shadow-[0_0_30px_rgba(14,165,233,0.3)] transition-all duration-300 px-6 py-2.5 rounded-full text-sm font-bold"
              >
                Start Your Project
              </Link>
            )}
          </div>
        </div>

        {/* Mobile Toggle */}
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="lg:hidden w-12 h-12 flex items-center justify-center rounded-xl bg-white/[0.05] border border-white/10 backdrop-blur-md"
          aria-label="Toggle menu"
        >
          <svg className="h-5 w-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            {isOpen ? (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            ) : (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" />
            )}
          </svg>
        </button>
      </div>

      {/* Mobile Menu */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0, y: -20 }}
            animate={{ opacity: 1, height: 'auto', y: 0 }}
            exit={{ opacity: 0, height: 0, y: -20 }}
            transition={{ duration: 0.3 }}
            className="lg:hidden mt-4 bg-obsidian/90 backdrop-blur-xl border border-white/10 rounded-2xl overflow-hidden shadow-2xl"
          >
            <div className="px-4 py-4 space-y-2">
              {navLinks.map((link, i) => (
                <motion.div
                  key={link.href}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.05 }}
                >
                  <Link
                    href={link.href}
                    onClick={() => setIsOpen(false)}
                    className={`block py-3 px-4 rounded-xl text-sm font-medium transition-all ${
                      pathname === link.href
                        ? 'text-blue-400 bg-blue-400/10'
                        : 'text-white/70 hover:text-white hover:bg-white/5'
                    }`}
                  >
                    {link.label}
                  </Link>
                </motion.div>
              ))}
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.3 }}
                className="pt-4 border-t border-white/10"
              >
                <div className="flex items-center gap-2 mb-4 font-mono text-xs uppercase tracking-[0.2em] text-white/50 px-4">
                  <span className="w-1.5 h-1.5 rounded-full bg-blue-400 animate-pulse-fast inline-block" />
                  System Online
                </div>
                <Link
                  href="/contact"
                  onClick={() => setIsOpen(false)}
                  className="bg-blue-400 block text-center text-black font-bold px-6 py-4 rounded-xl text-sm"
                >
                  Start Your Project
                </Link>
              </motion.div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
}

'use client';

import { Canvas } from '@react-three/fiber';
import { View, Preload } from '@react-three/drei';
import { useRef } from 'react';

export default function PerformanceManager({ children }: { children: React.ReactNode }) {
  const container = useRef<HTMLDivElement>(null);

  return (
    <div ref={container} className="relative w-full">
      {children}
      <Canvas
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '100vw',
          height: '100vh',
          pointerEvents: 'none',
          zIndex: -1,
        }}
        eventSource={container as any}
        frameloop="always" // Use always for smooth transitions, but keep DPR low
        dpr={[1, 1.2]}
        gl={{ 
          antialias: false,
          alpha: true,
          powerPreference: 'high-performance',
          stencil: false,
          depth: true
        }}
        performance={{ min: 0.5 }}
      >
        <View.Port />
      </Canvas>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { gsap } from 'gsap';

export default function Preloader() {
  const [loading, setLoading] = useState(true);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    let animationFrameId: number;
    const startTime = Date.now();
    const duration = 1500; // 1.5s total loading time

    const updateProgress = () => {
      const elapsed = Date.now() - startTime;
      const newProgress = Math.min((elapsed / duration) * 100, 100);

      setProgress(newProgress);

      if (newProgress < 100) {
        animationFrameId = requestAnimationFrame(updateProgress);
      } else {
        setTimeout(() => setLoading(false), 500);
      }
    };

    animationFrameId = requestAnimationFrame(updateProgress);

    return () => cancelAnimationFrame(animationFrameId);
  }, []);

  const handleSkip = () => {
    setLoading(false);
  };

  return (
    <AnimatePresence>
      {loading && (
        <motion.div
          initial={{ opacity: 1 }}
          exit={{ opacity: 0, transition: { duration: 0.8, ease: 'easeInOut' } }}
          className="fixed inset-0 z-[10000] bg-black flex flex-col items-center justify-center overflow-hidden"
        >
          {/* Skip Button */}
          <motion.button
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.5 }}
            onClick={handleSkip}
            className="absolute top-10 right-10 z-50 px-4 py-2 bg-white/5 hover:bg-white/10 border border-white/10 rounded-full font-mono text-[10px] uppercase tracking-widest text-white/50 hover:text-white transition-all group"
          >
            SKIP INTRO <span className="inline-block group-hover:translate-x-1 transition-transform">→</span>
          </motion.button>

          <div className="relative w-80">
            {/* Progress Label */}
            <div className="flex justify-between items-end mb-4">
              <div className="space-y-1">
                <p className="text-[10px] font-mono text-blue-400 uppercase tracking-[0.3em]">System Initialization</p>
                <h2 className="text-xl font-heading font-black text-white uppercase tracking-tighter">Vedastra AI Labs / Loading...</h2>
              </div>
              <p className="text-xl font-mono text-blue-400 font-bold">{Math.floor(progress)}%</p>
            </div>

            {/* Progress Bar Container */}
            <div className="h-[2px] w-full bg-white/5 relative overflow-hidden">
              <motion.div 
                className="absolute top-0 left-0 h-full bg-blue-400 shadow-[0_0_15px_#0ea5e9]"
                initial={{ width: 0 }}
                animate={{ width: `${progress}%` }}
                transition={{ duration: 0.1 }}
              />
            </div>

            {/* Status Messages */}
            <div className="mt-8 h-4 overflow-hidden">
              <AnimatePresence mode="wait">
                <motion.p
                  key={Math.floor(progress / 25)}
                  initial={{ y: 20, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  exit={{ y: -20, opacity: 0 }}
                  className="text-[9px] font-mono text-white/30 uppercase tracking-widest text-center"
                >
                  {progress < 25 && "Loading Digital Assets..."}
                  {progress >= 25 && progress < 50 && "Establishing Neural Links..."}
                  {progress >= 50 && progress < 75 && "Syncing UI Buffers..."}
                  {progress >= 75 && "Finalizing Environment..."}
                </motion.p>
              </AnimatePresence>
            </div>
          </div>

          {/* Decorative Corners */}
          <div className="absolute top-10 left-10 w-4 h-4 border-t border-l border-white/20" />
          <div className="absolute bottom-10 left-10 w-4 h-4 border-b border-l border-white/20" />
          <div className="absolute bottom-10 right-10 w-4 h-4 border-b border-r border-white/20" />
        </motion.div>
      )}
    </AnimatePresence>
  );
}

