            <meshStandardMaterial color="#ef4444" metalness={1} roughness={0.1} />
          </mesh>
          <mesh position={[2.4, -0.2, 0]}>
            <cylinderGeometry args={[0.2, 0.2, 2.6, 6]} />
            <meshStandardMaterial color="#ef4444" metalness={1} roughness={0.1} />
          </mesh>

          {/* Floating Red Neon "Brain" Core */}
          <group position={[0, -0.2, 0.1]}>
